import { useEffect, useState } from "react";
import API from "../services/api";
import "../styles/ComparePlayers.css";

function ComparePlayers() {
  const [players, setPlayers] = useState([]);
  const [player1, setPlayer1] = useState(null);
  const [player2, setPlayer2] = useState(null);

  useEffect(() => {
    API.get("/players").then((res) => setPlayers(res.data));
  }, []);

  const handleSelect1 = (e) => {
    const player = players.find((p) => p._id === e.target.value);
    setPlayer1(player);
  };

  const handleSelect2 = (e) => {
    const player = players.find((p) => p._id === e.target.value);
    setPlayer2(player);
  };

  const getWinner = (p1, p2) => {
    const metrics = [
      { p1: p1.runs || 0, p2: p2.runs || 0 },
      { p1: p1.battingAvg || 0, p2: p2.battingAvg || 0 },
      { p1: p1.strikeRate || 0, p2: p2.strikeRate || 0 },
      { p1: p1.matches || 0, p2: p2.matches || 0 },
      { p1: p1.highScore || 0, p2: p2.highScore || 0 },
      { p1: p1.wickets || 0, p2: p2.wickets || 0 }
    ];

    let p1Wins = 0, p2Wins = 0;

    metrics.forEach(metric => {
      if (metric.p1 > metric.p2) p1Wins++;
      else if (metric.p2 > metric.p1) p2Wins++;
    });

    if (p1Wins > p2Wins) return { winner: p1.name, winnerId: 1 };
    if (p2Wins > p1Wins) return { winner: p2.name, winnerId: 2 };
    return { winner: "Tie", winnerId: 0 };
  };

  const StatRow = ({ label, val1, val2 }) => (
    <div className="stat-item" style={{ display: 'grid', gridTemplateColumns: '1fr 100px 1fr', textAlign: 'center', alignItems: 'center', padding: '15px 0' }}>
      <div style={{ fontSize: '1.2rem', fontWeight: '800', color: val1 > val2 ? 'var(--cyan)' : '#000' }}>{val1}</div>
      <div style={{ fontSize: '0.7rem', fontWeight: 'bold', color: '#666', textTransform: 'uppercase' }}>{label}</div>
      <div style={{ fontSize: '1.2rem', fontWeight: '800', color: val2 > val1 ? 'var(--cyan)' : '#000' }}>{val2}</div>
    </div>
  );

  return (
    <div className="page" style={{ padding: '20px' }}>
      <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>⚔️ Player Comparison</h2>

      <div style={{ display: 'flex', gap: '20px', justifyContent: 'center', marginBottom: '40px' }}>
        <select onChange={handleSelect1} style={{ padding: '10px', borderRadius: '8px', width: '200px' }}>
          <option value="">Select Player 1</option>
          {players.map((p) => (
            <option key={p._id} value={p._id}>{p.name}</option>
          ))}
        </select>
        <div style={{ alignSelf: 'center', fontWeight: 'bold', fontSize: '1.5rem' }}>VS</div>
        <select onChange={handleSelect2} style={{ padding: '10px', borderRadius: '8px', width: '200px' }}>
          <option value="">Select Player 2</option>
          {players.map((p) => (
            <option key={p._id} value={p._id}>{p.name}</option>
          ))}
        </select>
      </div>

      {player1 && player2 ? (
        <div className="card" style={{ maxWidth: '800px', margin: '0 auto', background: '#fff', padding: '30px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 100px 1fr', textAlign: 'center', marginBottom: '20px', borderBottom: '2px solid #eee', paddingBottom: '20px' }}>
            <div>
              <h3 style={{ margin: 0, color: 'var(--navy)' }}>{player1.name}</h3>
              <small>{player1.team}</small>
            </div>
            <div style={{ fontSize: '1.5rem' }}>🏆</div>
            <div>
              <h3 style={{ margin: 0, color: 'var(--navy)' }}>{player2.name}</h3>
              <small>{player2.team}</small>
            </div>
          </div>

          <StatRow label="Runs" val1={player1.runs || 0} val2={player2.runs || 0} />
          <StatRow label="Average" val1={player1.battingAvg || 0} val2={player2.battingAvg || 0} />
          <StatRow label="Strike Rate" val1={player1.strikeRate || 0} val2={player2.strikeRate || 0} />
          <StatRow label="Matches" val1={player1.matches || 0} val2={player2.matches || 0} />
          <StatRow label="Highest Score" val1={player1.highScore || 0} val2={player2.highScore || 0} />
          <StatRow label="Wickets" val1={player1.wickets || 0} val2={player2.wickets || 0} />
        </div>
      ) : (
        <p style={{ textAlign: 'center', color: '#666' }}>Please select two players to begin comparison.</p>
      )}
    </div>
  );
}

export default ComparePlayers;
